# Complete Suricata rule:
alert tcp any any -> $HOME_NET 22 (
  msg:"SSH Brute Force Attempt";
  flow:established;
  threshold:type both,
    track by_src,
    count 5,
    seconds 60;
  classtype:attempted-admin;
  sid:9001;
  rev:1;
)

import pyshark, json
from datetime import datetime

def extract_iocs(pcap_file):
    iocs = {'ips': set(), 'domains': set(),
            'urls': set(), 'user_agents': set()}

    # Extract IPs from all packets:
    for pkt in pyshark.FileCapture(pcap_file):
        try:
            iocs['ips'].add(pkt.ip.dst)
        except: pass

    # Extract DNS domains:
    for pkt in pyshark.FileCapture(pcap_file,
                                   display_filter='dns'):
        try:
            iocs['domains'].add(pkt.dns.qry_name)
        except: pass

    # Convert sets to sorted lists for JSON export:
    output = {k: sorted(v) for k, v in iocs.items()}
    output['timestamp'] = datetime.now().isoformat()

    with open('iocs.json', 'w') as f:
        json.dump(output, f, indent=2)
    return output
